/** Flat lookup: canonical value → { label, topLevel } */
export const CATEGORY_MAP: Record<string, { label: string; topLevel: string }> = (() => {
  const map: Record<string, { label: string; topLevel: string }> = {}
  for (const [topKey, subcats] of Object.entries(CATEGORY_TREE)) {
    for (const node of Object.values(subcats)) {
      map[node.value] = { label: node.label, topLevel: topKey }
    }
  }
  return map
})()

/** Look up a leaf node by its canonical value */
export function getCategoryNode(categoryValue: string): CategoryNode | undefined {
  // Check legacy mapping first
  const resolved = LEGACY_CATEGORY_MAP[categoryValue] ?? categoryValue
  for (const subcats of Object.values(CATEGORY_TREE)) {
    for (const node of Object.values(subcats)) {
      if (node.value === resolved) return node
    }
  }
  return undefined
}

/** Get the platform-specific category ID for a canonical value */
export function getPlatformCategoryId(
  categoryValue: string,
  platform: 'ebay' | 'vinted' | 'shopify' | 'etsy' | 'depop'
): string | undefined {
  const node = getCategoryNode(categoryValue)
  return node?.platforms[platform]?.id
}

/** Extract the top-level key from a canonical value */
/** Valid top-level keys for fallback resolution */
const TOP_LEVEL_KEYS = new Set(Object.keys(CATEGORY_TREE))

export function getTopLevelCategory(categoryValue: string): string {
  const resolved = LEGACY_CATEGORY_MAP[categoryValue] ?? categoryValue
  const entry = CATEGORY_MAP[resolved]
  if (entry) return entry.topLevel
  // Fallback: try progressively longer prefixes (handles multi-segment keys like 'home_garden')
  const parts = resolved.split('_')
  for (let i = parts.length - 1; i >= 1; i--) {
    const prefix = parts.slice(0, i).join('_')
    if (TOP_LEVEL_KEYS.has(prefix)) return prefix
  }
  return parts[0] ?? resolved
}

